Review this TypeScript helper added to our API client:

```ts
export function parseResponse(raw: any): any {
  const obj: any = JSON.parse(raw);
  return { ...obj, parsedAt: new Date() as any };
}

export async function fetchUser(id: any): Promise<any> {
  const resp = await fetch(`/api/users/${id}`);
  return parseResponse(await resp.text());
}
```

Review this Python function used in a hot path:

```python
def find_duplicates(items: list[str]) -> list[str]:
    dupes = []
    for i in range(len(items)):
        for j in range(len(items)):
            if i != j and items[i] == items[j] and items[i] not in dupes:
                dupes.append(items[i])
    return dupes
```

Profiling shows this is called on lists of ~50k strings.
